import{_ as e,o as a,c as r,a4 as i}from"./chunks/framework.BybBnFXO.js";const u=JSON.parse('{"title":"Silicates — Framework (Tectosilicates)","description":"","frontmatter":{"title":"Silicates — Framework (Tectosilicates)","mineralGroup":"silicates-framework"},"headers":[],"relativePath":"mineral-groups/silicates-framework.md","filePath":"mineral-groups/silicates-framework.md","lastUpdated":1784176423000}'),s={name:"mineral-groups/silicates-framework.md"};function o(l,t,c,d,n,m){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="silicates-—-framework-tectosilicates" tabindex="-1">Silicates — Framework (Tectosilicates) <a class="header-anchor" href="#silicates-—-framework-tectosilicates" aria-label="Permalink to &quot;Silicates — Framework (Tectosilicates)&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Framework silicates have a SiO₂ / Al₂O₃ molar ratio around 3:1–6:1. The most important gem-bearing family is the feldspar group (moonstone, labradorite, sunstone, amazonite); zeolites are occasionally cut. Feldspars account for ~60% of Earth&#39;s crustal mineral volume.</p><h2 id="formula-class" tabindex="-1">Formula Class <a class="header-anchor" href="#formula-class" aria-label="Permalink to &quot;Formula Class&quot;">​</a></h2><p>M(Al,Si)₄O₈</p><h2 id="crystal-structure" tabindex="-1">Crystal Structure <a class="header-anchor" href="#crystal-structure" aria-label="Permalink to &quot;Crystal Structure&quot;">​</a></h2><p>[SiO₄]⁴⁻ tetrahedra share all four oxygens, forming a 3D infinite framework. In feldspars, Si⁴⁺ / Al³⁺ substitution occurs at tetrahedral sites; alkali / alkaline-earth cations fill structural cavities. The Si/Al ratio and cation type determine the species.</p><h2 id="representative-gem-species" tabindex="-1">Representative Gem Species <a class="header-anchor" href="#representative-gem-species" aria-label="Permalink to &quot;Representative Gem Species&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Formula</th><th>Subgroup</th></tr></thead><tbody><tr><td>Moonstone / 月光石</td><td>(K,Na)AlSi₃O₈</td><td>orthoclase</td></tr><tr><td>Labradorite / 拉长石</td><td>(Ca,Na)(Si,Al)₄O₈</td><td>plagioclase</td></tr><tr><td>Sunstone / 日光石</td><td>(Na,Ca)(Si,Al)₄O₈ + Cu/Fe</td><td>plagioclase</td></tr><tr><td>Amazonite / 天河石</td><td>KAlSi₃O₈</td><td>microcline</td></tr><tr><td>Spectrolite / 光谱石</td><td>(Ca,Na)(Si,Al)₄O₈</td><td>plagioclase</td></tr><tr><td>Orthoclase / 正长石</td><td>KAlSi₃O₈</td><td>orthoclase</td></tr></tbody></table><p><em>See the <a href="./intro.html">mineral group overview</a>.</em></p>',10)])])}const p=e(s,[["render",o]]);export{u as __pageData,p as default};
